SELECT id, name, type, status, code, address, contact_person AS contactPerson, contact_phone AS contactPhone, principal_phone AS principalPhone, principal, staff_count AS staffCount, org_id AS orgId FROM tbl_organization_business
AND name LIKE CONCAT('%', #{request.name}, '%')
AND type = #{request.type}
AND status = #{request.status}
AND code = #{request.code}
AND address LIKE CONCAT('%', #{request.address}, '%')
AND contact_person LIKE CONCAT('%', #{request.contactPerson}, '%')
AND contact_phone LIKE CONCAT('%', #{request.contactPhone}, '%')
AND principal_phone LIKE CONCAT('%', #{request.principalPhone}, '%')
AND principal LIKE CONCAT('%', #{request.principal}, '%')
AND org_id = #{request.orgId}
AND deleted = 0
ORDER BY create_time DESC
